def create_page(key, title, desc, keywords, h1, intro, metrics, btn, sidebar, content):
    parts = key.split('/')
    canon = '/' + key if len(parts) == 2 else '/' + parts[0]

    if len(parts) == 2:
        os.makedirs(f"public/{parts[0]}", exist_ok=True)
        path = f"public/{parts[0]}/{parts[1]}/index.html"
    else:
        os.makedirs("public", exist_ok=True)
        path = f"public/{parts[0]}/index.html"

    os.makedirs(os.path.dirname(path), exist_ok=True)

    faqs = ', '.join([json.dumps({"@type":"Question","name":q,"acceptedAnswer":{"@type":"Answer","text":a}}) for q,a in [
        ("¿Cuanto tiempo tarda?","Maximo 15 minutos desde confirmacion."),
        ("¿Cual es el costo?","Solo el cambio del dia, sin comisiones."),
        ("¿Necesito documentos?","Solo foto de cupo y numero de cuenta."),
        ("¿Es seguro?","Si, operamos en sistema bancario formal."),
    ]])

    html = HTML_TPL.format(t=title, d=desc, k=keywords, c=canon, h=h1, i=intro, m=metrics, b=btn, s=sidebar, x=content, f=faqs)
    with open(path, 'w', encoding='utf-8') as f:
        f.write(html)
    return f"https://dolarexpress.cl{canon}/"

